from dataclasses import dataclass
from datetime import date
from typing import Literal

Jurisdiction = Literal["US", "EU", "UK", "OTHER"]
RiskLevel = Literal["LOW", "MEDIUM", "HIGH", "INDETERMINATE"]

@dataclass
class GenAIOutputRecord:
    output_id: str
    output_type: str               # "text", "code", "image", "audio"
    generating_model: str          # e.g. "gpt-4o-2024-05-13"
    prompt_author: str             # employee ID
    prompt_text: str
    human_creative_elements: list[str]  # specific choices made by the human author
    jurisdiction: Jurisdiction
    date_generated: date
    vendor_indemnification_applies: bool
    safety_filters_active: bool

    def human_authorship_likely(self) -> bool:
        """
        True if the record has plausible human authorship claims.
        Does NOT constitute legal advice — flag for IP counsel review.
        """
        return (
            len(self.human_creative_elements) >= 3 and
            len(self.prompt_text) > 200  # substantial creative prompt
        )

    def copyright_risk_level(self) -> RiskLevel:
        if not self.human_authorship_likely():
            if self.jurisdiction == "UK":
                return "MEDIUM"  # s.9(3) CDPA may apply but uncertain
            if self.jurisdiction in ("US", "EU"):
                return "HIGH"   # no protection — freely copyable AND potential training-data claims
        if not self.vendor_indemnification_applies:
            return "MEDIUM"     # human-authored but training-data risk remains
        if not self.safety_filters_active:
            return "MEDIUM"     # indemnification typically excludes filter-bypass outputs
        return "LOW"

    def ownership_assessment(self) -> str:
        if self.jurisdiction == "US":
            if self.human_authorship_likely():
                return "Human-authored elements may be copyrightable; AI portions are not."
            return "No copyright protection under current US law."
        if self.jurisdiction == "UK":
            if self.human_authorship_likely():
                return "Human-authored elements may attract copyright. AI portions may fall under s.9(3) CDPA."
            return "Potentially protected under s.9(3) CDPA as computer-generated work — seek UK IP counsel."
        if self.jurisdiction == "EU":
            if self.human_authorship_likely():
                return "Human-authored elements may attract copyright under InfoSoc Directive."
            return "No copyright protection under current EU law. Sui generis AI right not yet enacted."
        return "INDETERMINATE — jurisdiction-specific advice required."

@dataclass
class OutputCopyrightPolicy:
    """
    Encodes the enterprise's operational copyright policy for AI outputs.
    Does NOT replace legal counsel — it operationalises agreed policy decisions.
    """
    commercial_use_requires_human_review: bool = True
    customer_facing_requires_edit: bool = True
    minimum_human_creative_elements_for_claim: int = 3
    require_vendor_indemnification_for_product_use: bool = True
    similarity_check_required_for_code: bool = True

    def can_publish(self, record: GenAIOutputRecord, is_commercial: bool) -> tuple[bool, list[str]]:
        blockers: list[str] = []

        if is_commercial and self.commercial_use_requires_human_review:
            if not record.human_authorship_likely():
                blockers.append(
                    "Commercial use requires documented human creative contribution (≥3 elements)."
                )

        if self.require_vendor_indemnification_for_product_use and is_commercial:
            if not record.vendor_indemnification_applies:
                blockers.append(
                    "Vendor IP indemnification must be confirmed before commercial use."
                )
            if not record.safety_filters_active:
                blockers.append(
                    "Safety filters were disabled — indemnification may not apply. Legal review required."
                )

        if self.similarity_check_required_for_code and record.output_type == "code":
            blockers.append(
                "Code outputs require similarity check against known copyrighted code (run before deploy)."
            )

        return (len(blockers) == 0, blockers)

    def policy_summary(self) -> str:
        return (
            "Copyright Policy: "
            f"Human review={'required' if self.commercial_use_requires_human_review else 'optional'} for commercial; "
            f"Indemnification={'required' if self.require_vendor_indemnification_for_product_use else 'optional'} for product; "
            f"Code similarity check={'required' if self.similarity_check_required_for_code else 'optional'}."
        )
